{"name": "write_file", "arguments": {"path": "templates/index.html", "content": "<!DOCTYPE html>
<html lang="ko">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>부동산 뉴스 목록</title>
</head>
<body>
    <h1>부동산 뉴스 목록</h1>
    <ul id="news-list"></ul>

    <script>
        // Sample data
        const newsData = [
            { title: '제목 1', source: '출처 1', summary: '핵심 요약 1', link: 'https://example.com/news1' },
            { title: '제목 2', source: '출처 2', summary: '핵심 요약 2', link: 'https://example.com/news2' }
        ];

        // Function to render news items
        function renderNewsItems(data) {
            const list = document.getElementById('news-list');
            data.forEach(item => {
                const li = document.createElement('li');
                const a = document.createElement('a');
                a.href = item.link;
                a.target = '_blank';
                a.textContent = `${item.title} - ${item.source}
${item.summary}`;
                li.appendChild(a);
                list.appendChild(li);
            });
        }

        // Render news items on page load
        renderNewsItems(newsData);
    </script>
</body>
</html>"}}
```
